          </div>

          <div class="form-group-compact">
            <label>Adresse complète *</label>
            <input *ngIf="isEditMode" type="text" name="address" [(ngModel)]="profile.address" required placeholder="Ex: Ariana, Tunis, Tunisie">
            <div *ngIf="!isEditMode" class="static-text-compact">{{ profile.address || 'Non renseigné' }}</div>
          </div>
        </div>
        
      </div>

