                <i class="bi bi-key-fill"></i> Modifier
              </button>
            </ng-container>
            <ng-container *ngIf="isPasswordEditMode">
              <button type="button" class="btn-cancel-compact" style="padding: 5px 10px; font-size: 12px; margin-right: 5px;" (click)="togglePasswordEditMode(false)">Annuler</button>
              <button type="button" (click)="onUpdatePassword($event)" class="btn-save-compact btn-dark-theme" style="padding: 5px 12px; font-size: 12px;"><i class="bi bi-shield-check"></i> Enregistrer</button>
            </ng-container>
          </div>
        </div>

        <!-- Champs Sécurité -->
        <div class="compact-form-grid">
          <div class="form-group-compact">
            <label>Mot de passe actuel *</label>
            <input *ngIf="isPasswordEditMode" type="password" name="current_password" [(ngModel)]="passwordData.currentPassword" required placeholder="••••••••">
            <div *ngIf="!isPasswordEditMode" class="static-text-compact text-muted-dots">••••••••••••</div>
          </div>

          <div class="form-group-compact">
            <label>Nouveau mot de passe *</label>
            <input *ngIf="isPasswordEditMode" type="password" name="new_password" [(ngModel)]="passwordData.newPassword" required placeholder="Min. 6 caractères">
            <div *ngIf="!isPasswordEditMode" class="static-text-compact text-muted-dots">••••••••••••</div>
          </div>

          <div class="form-group-compact">
            <label>Confirmer le mot de passe *</label>
            <input *ngIf="isPasswordEditMode" type="password" name="confirm_password" [(ngModel)]="passwordData.confirmPassword" required placeholder="••••••••">
            <div *ngIf="!isPasswordEditMode" class="static-text-compact text-muted-dots">••••••••••••</div>
          </div>
        </div>
        
      </div>

    </div>
